(window.webpackJsonp=window.webpackJsonp||[]).push([[78],{705:function(r,n){r.exports="\x3c!-- \r\ntitle: Nginx\r\nsort: \r\n--\x3e \r\n\r\n# Nginx入门\r\n\r\n> [OpenResty](http://openresty.org/cn/)\r\n\r\n## 配置\r\n\r\n```bash\r\n# 默认配置文件\r\nvim /etc/nginx/sites-enabled/default \r\nnginx -s reload\r\n```\r\n\r\n## 默认\r\n\r\n```nginx\r\n# /etc/nginx/sites-enable/default\r\nserver {\r\n\tlisten 80;\r\n    server_name localhost;\r\n\r\n\tlocation / {\r\n\t\troot /var/www/html;\r\n\t\tindex index.html index.htm index.nginx-debian.html;\r\n\t}\r\n}\r\n```\r\n\r\n## 详解\r\n\r\n```nginx\r\n# 全局块\r\nuser administrator administrators;  # 配置用户或者组，默认为nobody nobody。\r\nworker_processes 2;  # 允许生成的进程数，默认为1\r\npid /nginx/pid/nginx.pid;   # 指定nginx进程运行文件存放地址\r\nerror_log log/error.log debug;  # 制定日志路径，级别。\r\n# 可以放入全局块，http块，server块\r\n# 级别为：debug|info|notice|warn|error|crit|alert|emerg\r\n\r\nevents {         # events块\r\n    accept_mutex on;   # 设置网路连接序列化，防止惊群现象发生，默认为on\r\n    multi_accept on;  # 设置一个进程是否同时接受多个网络连接，默认为off\r\n    #use epoll;      # 事件驱动模型，select|poll|kqueue|epoll|resig|/dev/poll|eventport\r\n    worker_connections  1024;    # 最大连接数，默认为512\r\n}\r\n\r\nhttp {     \t# http块\r\n    include       mime.types;   # 文件扩展名与文件类型映射表\r\n    default_type  application/octet-stream; # 默认文件类型，默认为text/plain\r\n    # access_log off; # 取消服务日志    \r\n    log_format myFormat '$remote_addr–$remote_user [$time_local] $request $status $body_bytes_sent $http_referer $http_user_agent $http_x_forwarded_for'; # 自定义格式\r\n    access_log log/access.log myFormat;  # combined为日志格式的默认值\r\n    sendfile on;   # 允许sendfile方式传输文件，默认为off，可以在http块，server块，location块。\r\n    sendfile_max_chunk 100k;  # 每个进程每次调用传输数量不能大于设定的值，默认为0，即不设上限。\r\n    keepalive_timeout 65;  # 连接超时时间，默认为75s，可以在http，server，location块。\r\n    # 负载均衡\r\n    upstream mysvr {   \r\n      server 127.0.0.1:7878;\r\n      server 192.168.10.121:3333 backup;  # 热备\r\n    }\r\n    error_page 404 https://www.baidu.com; # 错误页\r\n\r\n    server {       # server块 \r\n        keepalive_requests 120; # 单连接请求上限次数。\r\n        listen       4545;   # 监听端口\r\n        server_name  127.0.0.1;   # 监听地址         \r\n        location / {  # location块\r\n           # root path;  # 根目录\r\n           # index vv.txt;  # 设置默认页\r\n           proxy_pass  http://mysvr;  # 请求转向mysvr 定义的服务器列表\r\n           echo \"fzf\";\t\t# 输出内容\r\n           deny 127.0.0.1;  # 拒绝的ip\r\n           allow 172.18.5.54; # 允许的ip     \r\n        }\r\n        location \r\n        {\r\n            ...\r\n        }\r\n    }\r\n    server\r\n    {\r\n      ...\r\n    }\r\n}\r\n```\r\n\r\n## 基础\r\n\r\n```nginx\r\nlocation /test {\r\n\r\n}\r\n```\r\n\r\n## 实例\r\n\r\n- 作为文件服务器使用\r\n\r\n```nginx\r\nlocation /app {\r\n    # 遍历目录\r\n    autoindex on;\r\n    # 文件大小显示\r\n    autoindex_exact_size off;\r\n    # 显示服务器时间\r\n    autoindex_localtime on;\r\n    # 中文文件夹转码\r\n    charset utf-8;\r\n}\r\n\r\n```\r\n\r\n- 负载均衡\r\n\r\n```nginx\r\n# 负载均衡 权重\r\nupstream group1{\r\n\tserver 192.168.0.1:80 weight=2;\r\n\tserver 192.168.0.1:8080 weight=1;\r\n}\r\n\r\nserver{\r\n    location /test/ {\r\n        # 随机重定向到两个网页\r\n        proxy_pass http://group1/;\r\n    }\r\n}\r\n```\r\n\r\n"}}]);